@* Displays a single task card with title, assignee, priority badge, due date, and move buttons *@

<div class="task-card">
    <div class="task-card-header">
        <span class="task-title">@Task.Title</span>
        <span class="priority-badge @GetPriorityClass()">@Task.Priority</span>
    </div>
    <div class="task-card-body">
        <span class="task-assignee">👤 @Task.Assignee</span>
        <span class="task-due">📅 @Task.DueDate.ToString("MMM dd")</span>
    </div>
    <div class="task-card-actions">
        @if (ShowMoveLeft)
        {
            <button class="btn-move" @onclick="() => OnMoveLeft.InvokeAsync(Task.Id)" disabled="@IsMoving">
                ← Move Left
            </button>
        }
        @if (ShowMoveRight)
        {
            <button class="btn-move" @onclick="() => OnMoveRight.InvokeAsync(Task.Id)" disabled="@IsMoving">
                Move Right →
            </button>
        }
    </div>
</div>

@code {
    [Parameter, EditorRequired]
    public TaskItem Task { get; set; } = default!;

    [Parameter]
    public bool ShowMoveLeft { get; set; }

    [Parameter]
    public bool ShowMoveRight { get; set; }

    [Parameter]
    public EventCallback<int> OnMoveLeft { get; set; }

    [Parameter]
    public EventCallback<int> OnMoveRight { get; set; }

    [Parameter]
    public bool IsMoving { get; set; }

    private string GetPriorityClass() => Task.Priority switch
    {
        "High" => "priority-high",
        "Medium" => "priority-medium",
        "Low" => "priority-low",
        _ => ""
    };
}

@* Inline form to create a new task within a column *@

<div class="add-task-form">
    <div class="form-field">
        <label>Title</label>
        <input type="text" @bind="title" placeholder="Task title" />
    </div>
    <div class="form-field">
        <label>Assignee</label>
        <input type="text" @bind="assignee" placeholder="Assignee name" />
    </div>
    <div class="form-field">
        <label>Priority</label>
        <select @bind="priority">
            <option value="High">High</option>
            <option value="Medium">Medium</option>
            <option value="Low">Low</option>
        </select>
    </div>
    <div class="form-field">
        <label>Due Date</label>
        <input type="date" @bind="dueDate" />
    </div>
    <div class="form-actions">
        <button class="btn-save" @onclick="HandleSave" disabled="@isSaving">
            @(isSaving ? "Saving..." : "Save")
        </button>
        <button class="btn-cancel" @onclick="HandleCancel" disabled="@isSaving">Cancel</button>
    </div>
    @if (!string.IsNullOrEmpty(errorMessage))
    {
        <div class="form-error">@errorMessage</div>
    }
</div>

@code {
    [Parameter, EditorRequired]
    public EventCallback<(string Title, string Assignee, string Priority, DateTime DueDate)> OnSave { get; set; }

    [Parameter, EditorRequired]
    public EventCallback OnCancel { get; set; }

    private string title = "";
    private string assignee = "";
    private string priority = "Medium";
    private DateTime dueDate = DateTime.Today.AddDays(7);
    private bool isSaving;
    private string? errorMessage;

    private async Task HandleSave()
    {
        errorMessage = null;

        if (string.IsNullOrWhiteSpace(title))
        {
            errorMessage = "Title is required.";
            return;
        }
        if (string.IsNullOrWhiteSpace(assignee))
        {
            errorMessage = "Assignee is required.";
            return;
        }

        isSaving = true;
        try
        {
            await OnSave.InvokeAsync((title, assignee, priority, dueDate));
        }
        catch (Exception ex)
        {
            errorMessage = $"Failed to save: {ex.Message}";
        }
        finally
        {
            isSaving = false;
        }
    }

    private async Task HandleCancel()
    {
        await OnCancel.InvokeAsync();
    }
}

@* Search bar for filtering tasks by title *@

<div class="board-search">
    <input type="text"
           placeholder="Search tasks by title..."
           value="@SearchText"
           @oninput="HandleInput" />
</div>

@code {
    [Parameter]
    public string SearchText { get; set; } = "";

    [Parameter, EditorRequired]
    public EventCallback<string> OnSearchChanged { get; set; }

    private async Task HandleInput(ChangeEventArgs e)
    {
        await OnSearchChanged.InvokeAsync(e.Value?.ToString() ?? "");
    }
}

@* A single Kanban column with header, task cards, and an add-task button/form *@

<div class="board-column">
    <div class="column-header">
        <h3>@Title</h3>
        <span class="column-count">@Tasks.Count</span>
    </div>

    <div class="column-body">
        @foreach (var task in Tasks)
        {
            <TaskCard Task="task"
                      ShowMoveLeft="ShowMoveLeft"
                      ShowMoveRight="ShowMoveRight"
                      OnMoveLeft="HandleMoveLeft"
                      OnMoveRight="HandleMoveRight"
                      IsMoving="movingTaskId == task.Id" />
        }
    </div>

    <div class="column-footer">
        @if (showAddForm)
        {
            <AddTaskForm OnSave="HandleAddTask" OnCancel="() => showAddForm = false" />
        }
        else
        {
            <button class="btn-add-task" @onclick="() => showAddForm = true">+ Add Task</button>
        }
    </div>
</div>

@code {
    [Parameter, EditorRequired]
    public string Title { get; set; } = "";

    [Parameter, EditorRequired]
    public string Status { get; set; } = "";

    [Parameter, EditorRequired]
    public List<TaskItem> Tasks { get; set; } = [];

    [Parameter]
    public bool ShowMoveLeft { get; set; }

    [Parameter]
    public bool ShowMoveRight { get; set; }

    /// <summary>Raised when a task should move to the left column. Payload: (taskId, newStatus).</summary>
    [Parameter, EditorRequired]
    public EventCallback<(int TaskId, string NewStatus)> OnMoveTask { get; set; }

    /// <summary>Raised after a new task is created so the parent can refresh.</summary>
    [Parameter, EditorRequired]
    public EventCallback<(string Title, string Assignee, string Priority, DateTime DueDate)> OnAddTask { get; set; }

    private bool showAddForm;
    private int? movingTaskId;

    private async Task HandleMoveLeft(int taskId)
    {
        movingTaskId = taskId;
        try
        {
            var newStatus = Status switch
            {
                "In Progress" => "To Do",
                "Done" => "In Progress",
                _ => Status
            };
            await OnMoveTask.InvokeAsync((taskId, newStatus));
        }
        finally
        {
            movingTaskId = null;
        }
    }

    private async Task HandleMoveRight(int taskId)
    {
        movingTaskId = taskId;
        try
        {
            var newStatus = Status switch
            {
                "To Do" => "In Progress",
                "In Progress" => "Done",
                _ => Status
            };
            await OnMoveTask.InvokeAsync((taskId, newStatus));
        }
        finally
        {
            movingTaskId = null;
        }
    }

    private async Task HandleAddTask((string Title, string Assignee, string Priority, DateTime DueDate) data)
    {
        await OnAddTask.InvokeAsync(data);
        showAddForm = false;
    }
}

@page "/board"
@rendermode InteractiveServer
@inject ITaskService TaskService

<PageTitle>Kanban Board</PageTitle>

<h2>Kanban Board</h2>

@if (isLoading)
{
    <div class="board-loading">Loading tasks...</div>
}
else if (errorMessage is not null)
{
    <div class="board-error">
        <p>@errorMessage</p>
        <button @onclick="LoadTasks">Retry</button>
    </div>
}
else
{
    <BoardStats Tasks="allTasks" />
    <BoardSearchBar SearchText="@searchText" OnSearchChanged="HandleSearchChanged" />

    <div class="board-columns">
        <BoardColumn Title="To Do"
                     Status="To Do"
                     Tasks="GetFilteredTasks("To Do")"
                     ShowMoveLeft="false"
                     ShowMoveRight="true"
                     OnMoveTask="HandleMoveTask"
                     OnAddTask="args => HandleAddTask(args, "To Do")" />

        <BoardColumn Title="In Progress"
                     Status="In Progress"
                     Tasks="GetFilteredTasks("In Progress")"
                     ShowMoveLeft="true"
                     ShowMoveRight="true"
                     OnMoveTask="HandleMoveTask"
                     OnAddTask="args => HandleAddTask(args, "In Progress")" />

        <BoardColumn Title="Done"
                     Status="Done"
                     Tasks="GetFilteredTasks("Done")"
                     ShowMoveLeft="true"
                     ShowMoveRight="false"
                     OnMoveTask="HandleMoveTask"
                     OnAddTask="args => HandleAddTask(args, "Done")" />
    </div>
}

@code {
    private List<TaskItem> allTasks = [];
    private string searchText = "";
    private bool isLoading = true;
    private string? errorMessage;

    protected override async Task OnInitializedAsync()
    {
        await LoadTasks();
    }

    private async Task LoadTasks()
    {
        isLoading = true;
        errorMessage = null;
        try
        {
            allTasks = await TaskService.GetAllTasksAsync();
        }
        catch (Exception ex)
        {
            errorMessage = $"Failed to load tasks: {ex.Message}";
        }
        finally
        {
            isLoading = false;
        }
    }

    private List<TaskItem> GetFilteredTasks(string status)
    {
        var tasks = allTasks.Where(t => t.Status == status);
        if (!string.IsNullOrWhiteSpace(searchText))
        {
            tasks = tasks.Where(t => t.Title.Contains(searchText, StringComparison.OrdinalIgnoreCase));
        }
        return tasks.ToList();
    }

    private void HandleSearchChanged(string text)
    {
        searchText = text;
    }

    private async Task HandleMoveTask((int TaskId, string NewStatus) args)
    {
        await TaskService.UpdateTaskStatusAsync(args.TaskId, args.NewStatus);
        var task = allTasks.First(t => t.Id == args.TaskId);
        var index = allTasks.IndexOf(task);
        allTasks[index] = task with { Status = args.NewStatus };
    }

    private async Task HandleAddTask(
        (string Title, string Assignee, string Priority, DateTime DueDate) args,
        string status)
    {
        var created = await TaskService.CreateTaskAsync(args.Title, args.Assignee, args.Priority, args.DueDate);
        // The service creates with a default status; ensure it matches the column
        allTasks.Add(created with { Status = status });
    }
}

/* Board layout */
::deep .board-columns {
    display: flex;
    gap: 1rem;
    margin-top: 1rem;
    align-items: flex-start;
}

/* Stats bar */
::deep .board-stats {
    display: flex;
    gap: 1.5rem;
    padding: 0.75rem 1rem;
    background: #f0f4f8;
    border-radius: 8px;
    margin-bottom: 0.75rem;
}

::deep .stat-item {
    display: flex;
    flex-direction: column;
    align-items: center;
}

::deep .stat-value {
    font-size: 1.25rem;
    font-weight: 700;
}

::deep .stat-label {
    font-size: 0.75rem;
    color: #64748b;
    text-transform: uppercase;
}

::deep .stat-overdue .stat-value {
    color: #dc2626;
}

/* Search */
::deep .board-search {
    margin-bottom: 1rem;
}

::deep .board-search input {
    width: 100%;
    padding: 0.5rem 0.75rem;
    border: 1px solid #cbd5e1;
    border-radius: 6px;
    font-size: 0.9rem;
}

/* Column */
::deep .board-column {
    flex: 1;
    min-width: 250px;
    background: #f8fafc;
    border-radius: 8px;
    padding: 0.75rem;
    display: flex;
    flex-direction: column;
    gap: 0.5rem;
}

::deep .column-header {
    display: flex;
    justify-content: space-between;
    align-items: center;
    padding-bottom: 0.5rem;
    border-bottom: 2px solid #e2e8f0;
}

::deep .column-header h3 {
    margin: 0;
    font-size: 1rem;
}

::deep .column-count {
    background: #e2e8f0;
    border-radius: 999px;
