@page "/board"
@rendermode InteractiveServer
@inject ITaskService TaskService

<PageTitle>Kanban Board</PageTitle>

<h2>Kanban Board</h2>

@if (isLoading)
{
    <div class="board-loading">Loading tasks...</div>
}
else if (errorMessage is not null)
{
    <div class="board-error">
        <p>@errorMessage</p>
        <button @onclick="LoadTasks">Retry</button>
    </div>
}
else
{
    <BoardStats Tasks="allTasks" />
    <BoardSearchBar SearchText="@searchText" OnSearchChanged="HandleSearchChanged" />

    <div class="board-columns">
        <BoardColumn Title="To Do"
                     Status="To Do"
                     Tasks="GetFilteredTasks("To Do")"
                     ShowMoveLeft="false"
                     ShowMoveRight="true"
                     OnMoveTask="HandleMoveTask"
                     OnAddTask="args => HandleAddTask(args, "To Do")" />

        <BoardColumn Title="In Progress"
                     Status="In Progress"
                     Tasks="GetFilteredTasks("In Progress")"
                     ShowMoveLeft="true"
                     ShowMoveRight="true"
                     OnMoveTask="HandleMoveTask"
                     OnAddTask="args => HandleAddTask(args, "In Progress")" />

        <BoardColumn Title="Done"
                     Status="Done"
                     Tasks="GetFilteredTasks("Done")"
                     ShowMoveLeft="true"
                     ShowMoveRight="false"
                     OnMoveTask="HandleMoveTask"
                     OnAddTask="args => HandleAddTask(args, "Done")" />
    </div>
}

@code {
    private List<TaskItem> allTasks = [];
    private string searchText = "";
    private bool isLoading = true;
    private string? errorMessage;

    protected override async Task OnInitializedAsync()
    {
        await LoadTasks();
    }

    private async Task LoadTasks()
    {
        isLoading = true;
        errorMessage = null;
        try
        {
            allTasks = await TaskService.GetAllTasksAsync();
        }
        catch (Exception ex)
        {
            errorMessage = $"Failed to load tasks: {ex.Message}";
        }
        finally
        {
            isLoading = false;
        }
    }

    private List<TaskItem> GetFilteredTasks(string status)
    {
        var tasks = allTasks.Where(t => t.Status == status);
        if (!string.IsNullOrWhiteSpace(searchText))
        {
            tasks = tasks.Where(t => t.Title.Contains(searchText, StringComparison.OrdinalIgnoreCase));
        }
        return tasks.ToList();
    }

    private void HandleSearchChanged(string text)
    {
        searchText = text;
    }

    private async Task HandleMoveTask((int TaskId, string NewStatus) args)
    {
        await TaskService.UpdateTaskStatusAsync(args.TaskId, args.NewStatus);
        var task = allTasks.First(t => t.Id == args.TaskId);
        var index = allTasks.IndexOf(task);
        allTasks[index] = task with { Status = args.NewStatus };
    }

    private async Task HandleAddTask(
        (string Title, string Assignee, string Priority, DateTime DueDate) args,
        string status)
    {
        var created = await TaskService.CreateTaskAsync(args.Title, args.Assignee, args.Priority, args.DueDate);
        // The service creates with a default status; ensure it matches the column
        allTasks.Add(created with { Status = status });
    }
}

