{"file_text": "@* A single Kanban column with header, task cards, and an add-task button/form *@

<div class="board-column">
    <div class="column-header">
        <h3>@Title</h3>
        <span class="column-count">@Tasks.Count</span>
    </div>

    <div class="column-body">
        @foreach (var task in Tasks)
        {
            <TaskCard Task="task"
                      ShowMoveLeft="ShowMoveLeft"
                      ShowMoveRight="ShowMoveRight"
                      OnMoveLeft="HandleMoveLeft"
                      OnMoveRight="HandleMoveRight"
                      IsMoving="movingTaskId == task.Id" />
        }
    </div>

    <div class="column-footer">
        @if (showAddForm)
        {
            <AddTaskForm OnSave="HandleAddTask" OnCancel="() => showAddForm = false" />
        }
        else
        {
            <button class="btn-add-task" @onclick="() => showAddForm = true">+ Add Task</button>
        }
    </div>
</div>

@code {
    [Parameter, EditorRequired]
    public string Title { get; set; } = "";

    [Parameter, EditorRequired]
    public string Status { get; set; } = "";

    [Parameter, EditorRequired]
    public List<TaskItem> Tasks { get; set; } = [];

    [Parameter]
    public bool ShowMoveLeft { get; set; }

    [Parameter]
    public bool ShowMoveRight { get; set; }

    [Parameter, EditorRequired]
    public EventCallback<(int TaskId, string NewStatus)> OnMoveTask { get; set; }

    [Parameter, EditorRequired]
    public EventCallback<(string Title, string Assignee, string Priority, DateTime DueDate)> OnAddTask { get; set; }

    private bool showAddForm;
    private int? movingTaskId;

    private async Task HandleMoveLeft(int taskId)
    {
        movingTaskId = taskId;
        try
        {
            var newStatus = Status switch
            {
                "In Progress" => "To Do",
                "Done" => "In Progress",
                _ => Status
            };
            await OnMoveTask.InvokeAsync((taskId, newStatus));
        }
        finally
        {
            movingTaskId = null;
        }
    }

    private async Task HandleMoveRight(int taskId)
    {
        movingTaskId = taskId;
        try
        {
            var newStatus = Status switch
            {
                "To Do" => "In Progress",
                "In Progress" => "Done",
                _ => Status
            };
            await OnMoveTask.InvokeAsync((taskId, newStatus));
        }
        finally
        {
            movingTaskId = null;
        }
    }

    private async Task HandleAddTask((string Title, string Assignee, string Priority, DateTime DueDate) data)
    {
        await OnAddTask.InvokeAsync(data);
        showAddForm = false;
    }
}
