+    font-size: 1.25rem;
+    font-weight: 700;
+}
+
+::deep .stat-label {
+    font-size: 0.75rem;
+    color: #64748b;
+    text-transform: uppercase;
+}
+
+::deep .stat-overdue .stat-value {
+    color: #dc2626;
+}
+
+/* Search */
+::deep .board-search {
+    margin-bottom: 1rem;
+}
+
+::deep .board-search input {
+    width: 100%;
+    padding: 0.5rem 0.75rem;
+    border: 1px solid #cbd5e1;
+    border-radius: 6px;
+    font-size: 0.9rem;
+}
+
+/* Column */
+::deep .board-column {
+    flex: 1;
+    min-width: 250px;
+    background: #f8fafc;
+    border-radius: 8px;
+    padding: 0.75rem;
+    display: flex;
+    flex-direction: column;
+    gap: 0.5rem;
+}
+
+::deep .column-header {
+    display: flex;
+    justify-content: space-between;
+    align-items: center;
+    padding-bottom: 0.5rem;
+    border-bottom: 2px solid #e2e8f0;
+}
+
+::deep .column-header h3 {
+    margin: 0;
+    font-size: 1rem;
+}
+
+::deep .column-count {
+    background: #e2e8f0;
+    border-radius: 999px;
+    padding: 0.125rem 0.5rem;
+    font-size: 0.8rem;
+    font-weight: 600;
+}
+
+::deep .column-body {
+    display: flex;
+    flex-direction: column;
+    gap: 0.5rem;
+    min-height: 60px;
+}
+
+/* Task card */
+::deep .task-card {
+    background: #fff;
+    border: 1px solid #e2e8f0;
+    border-radius: 6px;
+    padding: 0.625rem;
+    display: flex;
+    flex-direction: column;
+    gap: 0.375rem;
+}
+
+::deep .task-card-header {
+    display: flex;
+    justify-content: space-between;
+    align-items: flex-start;
+    gap: 0.5rem;
+}
+
+::deep .task-title {
+    font-weight: 600;
+    font-size: 0.9rem;
+    word-break: break-word;
+}
+
+::deep .priority-badge {
+    font-size: 0.7rem;
+    padding: 0.125rem 0.4rem;
+    border-radius: 4px;
+    font-weight: 600;
+    white-space: nowrap;
+}
+
+::deep .priority-high {
+    background: #fecaca;
+    color: #991b1b;
+}
+
+::deep .priority-medium {
+    background: #fef08a;
+    color: #854d0e;
+}
+
+::deep .priority-low {
+    background: #bbf7d0;
+    color: #166534;
+}
+
+::deep .task-card-body {
+    display: flex;
+    justify-content: space-between;
+    font-size: 0.8rem;
+    color: #64748b;
+}
+
+::deep .task-card-actions {
+    display: flex;
+    gap: 0.375rem;
+    margin-top: 0.25rem;
+}
+
+::deep .btn-move {
+    flex: 1;
+    padding: 0.25rem 0.5rem;
+    border: 1px solid #cbd5e1;
+    border-radius: 4px;
+    background: #fff;
+    cursor: pointer;
+    font-size: 0.75rem;
+}
+
+::deep .btn-move:hover:not(:disabled) {
+    background: #f1f5f9;
+}
+
+::deep .btn-move:disabled {
+    opacity: 0.5;
+    cursor: not-allowed;
+}
+
+/* Add task */
+::deep .btn-add-task {
+    width: 100%;
+    padding: 0.5rem;
+    border: 2px dashed #cbd5e1;
+    border-radius: 6px;
+    background: transparent;
+    color: #64748b;
+    cursor: pointer;
+    font-size: 0.85rem;
+}
+
+::deep .btn-add-task:hover {
+    border-color: #94a3b8;
+    color: #334155;
+}
+
+/* Add task form */
+::deep .add-task-form {
+    background: #fff;
+    border: 1px solid #e2e8f0;
+    border-radius: 6px;
+    padding: 0.75rem;
+    display: flex;
+    flex-direction: column;
+    gap: 0.5rem;
+}
+
+::deep .form-field {
+    display: flex;
+    flex-direction: column;
+    gap: 0.2rem;
+}
+
+::deep .form-field label {
+    font-size: 0.75rem;
+    font-weight: 600;
+    color: #475569;
+}
+
+::deep .form-field input,
+::deep .form-field select {
+    padding: 0.375rem 0.5rem;
+    border: 1px solid #cbd5e1;
+    border-radius: 4px;
+    font-size: 0.85rem;
+}
+
+::deep .form-actions {
+    display: flex;
+    gap: 0.375rem;
+}
+
+::deep .btn-save {
+    flex: 1;
+    padding: 0.375rem;
+    background: #2563eb;
+    color: #fff;
+    border: none;
+    border-radius: 4px;
+    cursor: pointer;
+    font-size: 0.85rem;
+}
+
+::deep .btn-save:hover:not(:disabled) {
+    background: #1d4ed8;
+}
+
+::deep .btn-save:disabled {
+    opacity: 0.6;
+    cursor: not-allowed;
+}
+
+::deep .btn-cancel {
+    flex: 1;
+    padding: 0.375rem;
+    background: #f1f5f9;
+    border: 1px solid #cbd5e1;
+    border-radius: 4px;
+    cursor: pointer;
+    font-size: 0.85rem;
+}
+
+::deep .btn-cancel:hover:not(:disabled) {
+    background: #e2e8f0;
+}
+
+::deep .form-error {
+    color: #dc2626;
+    font-size: 0.8rem;
+}
+
+/* Loading / Error */
+::deep .board-loading {
+    text-align: center;
+    padding: 2rem;
+    color: #64748b;
+}
+
+::deep .board-error {
+    text-align: center;
+    padding: 2rem;
+    color: #dc2626;
+}
+
+::deep .board-error button {
+    margin-top: 0.5rem;
+    padding: 0.375rem 1rem;
+    border: 1px solid #dc2626;
+    border-radius: 4px;
+    background: #fff;
+    color: #dc2626;
+    cursor: pointer;
+}
+

